import { useEffect, useState } from "react";
import { Player } from "../../objects/player";
import { GetPlayerGameStats } from "../../services/game-stat-service";
import { GameStat } from "../../objects/game-stat";
import { GetTotalAssists, GetTotalGSO, GetTotalGames, GetTotalGoals, GetTotalShots, GetTotalTackles, PositionString } from "../../utils/game-stats-util";
import { GetSeasons } from "../../services/season-service";
import { Season } from "../../objects/season";
import PlayerStatsTableRow from "./player-stats-table-row";

interface playerProps{
    player : Player
}

const PlayerCard = (playerProps : playerProps) => {     

    const [seasons, setSeasons] = useState<Season[] | null>(null);
    const [gameStats, setGameStats] = useState<GameStat[] | null>(null);
    
    useEffect(() => {
        GetSeasons().then(seasons => setSeasons(seasons));
        GetPlayerGameStats(playerProps.player.id).then(gameStats => setGameStats(gameStats));
        
    }, [playerProps.player.id]);

    var position = PositionString(playerProps.player.position);

    return(   
        <div className="col-sm-3">
            <div className="card">
                <div className="card-body">
                    <h5 className="card-title">{playerProps.player.firstname} {playerProps.player.surname} ({position})</h5>  
                    <table>
                        <thead>
                            <tr>
                                <th>Season</th>
                                <th>Div</th>
                                <th>Apps</th>
                                <th>Gls</th>
                                <th>Assists</th>
                                <th>GSO</th>
                                <th>Shots</th>                                
                            </tr>
                        </thead>
                        <tbody>
                            {seasons?.map(season => 
                                <PlayerStatsTableRow season={season} player={playerProps.player}></PlayerStatsTableRow>
                            )}
                        </tbody>
                    </table>                     
                </div>
            </div>
        </div>        
    )
}
export default PlayerCard;
